  async function personaIconPng(persona:Persona){if(/^data:image\/png;base64,/i.test(persona.icon))return new Uint8Array(await(await fetch(persona.icon)).arrayBuffer());const canvas=document.createElement('canvas');canvas.width=canvas.height=128;const context=canvas.getContext('2d')!;context.fillStyle='#17191e';context.fillRect(0,0,128,128);if(persona.icon){const image=new Image();image.src=persona.icon;await image.decode();context.drawImage(image,0,0,128,128);}else{context.fillStyle='#d8b36a';context.font='bold 56px serif';context.textAlign='center';context.textBaseline='middle';context.fillText((persona.name.trim()[0]||'★').toUpperCase(),64,68);}const blob=await new Promise<Blob>((resolve,reject)=>canvas.toBlob((value)=>value?resolve(value):reject(new Error('persona_png_icon_encode_failed')),'image/png'));return new Uint8Array(await blob.arrayBuffer());}
  function personaPngError(reason:unknown){const message=reason instanceof Error?reason.message:String(reason);if(message.includes('metadata_missing'))return'이 PNG에는 페르소나 정보가 없습니다.';if(message.includes('payload_too_large'))return'페르소나 정보가 너무 커서 가져올 수 없습니다.';return'깨졌거나 지원하지 않는 페르소나 PNG입니다.';}
  async function bindPersona(value:boolean){if(!profile||!personaLibrary)return;await personaLibrary.bind(profile.project.projectId,value?activePersona.id:null);personaBound=value;}
  async function bindPersonaId(id:string|null){if(!profile||!personaLibrary)return;await personaLibrary.bind(profile.project.projectId,id);boundPersonaId=id;personaBound=!!id;const selected=personas.find(p=>p.id===id);if(selected){activePersona=selected;session?.setPersona(selected);}else{const data=await personaLibrary.list(),global=personas.find(p=>p.id===data.index.activeId);if(global){activePersona=global;session?.setPersona(global);}}version+=1;}
  async function reloadPresets(id?:string){if(!presetLibrary)return;const stored=await presetLibrary.list();presets=stored.presets;activePreset=presets.find(p=>p.id===(id??stored.index.activeId))??presets[0]??defaultCardPreset();session?.setPreset(activePreset);version+=1;}
  async function selectPreset(id:string){await presetLibrary?.activate(id);await reloadPresets(id);}
  async function changePreset(value:PromptPreset){await presetLibrary?.save(value);await reloadPresets(value.id);}
  async function newPreset(){const value={...defaultCardPreset(),id:`preset-${crypto.randomUUID()}`,name:'새 프리셋'};await changePreset(value);}
  async function clonePreset(){const value=structuredClone(activePreset);value.id=`preset-${crypto.randomUUID()}`;value.name=`${value.name} 복사본`;await changePreset(value);}
  async function renamePreset(){const name=prompt('프리셋 이름',activePreset.name)?.trim();if(name)await changePreset({...activePreset,name});}
  async function removePreset(){if(presets.length<=1||!confirm('이 프리셋을 삭제할까요?'))return;await presetLibrary?.remove(activePreset.id);await reloadPresets();}
  async function importPresetFile(file:File){try{const imported=importRisuPreset(await decodeRisuPresetFile(new Uint8Array(await file.arrayBuffer()),file.name));await presetLibrary?.save(imported.preset);if(imported.provider.temperature!=null)settings.temperature=imported.provider.temperature;if(imported.provider.maxTokens!=null)settings.maxTokens=imported.provider.maxTokens;await reloadPresets(imported.preset.id);error=imported.unsupported.length?`미지원 항목 ${imported.unsupported.length}개를 비활성 보존했습니다.`:'';}catch(reason){error=reason instanceof Error?reason.message:String(reason);}}
  function exportPreset(){const blob=new Blob([JSON.stringify(activePreset,null,2)],{type:'application/json'}),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download=`${activePreset.name}.json`;a.click();URL.revokeObjectURL(url);}
  // 세션 재생성 대신 provider만 교체 — 재생성하면 런타임 전용인 체크포인트·대안이 유실된다(감사 #11).
  function numberSetting(key:keyof ProviderConfig,value:string){const number=value.trim()===''?undefined:Number(value);if(number===undefined||Number.isFinite(number))(settings as unknown as Record<string,unknown>)[key]=number;}
  function saveSettings(){localStorage.setItem('simbot.llm',JSON.stringify(settings));showSettings=false;if(session){session.setProvider(provider(),{provider:settings.provider,model:settings.model});session.setAux(auxConfig());session.setMaxContext(settings.maxContext);session.setEmbeddingProvider(settings.voyageKey?createVoyageProvider({apiKey:settings.voyageKey}):undefined);version+=1;}}
  function clearPortraits(){for(const url of new Set(Object.values(portraitUrls)))URL.revokeObjectURL(url);portraitUrls={};galleryAssets=[];spriteGroups=[];boundModules=[];}
  function installPortraits(manifest:Record<string,unknown>,files:Record<string,Uint8Array>){clearPortraits();for(const raw of (manifest.assets??[]) as Array<Record<string,unknown>>){const blob=raw.blob as Record<string,unknown>|null,path=String(blob?.path??''),bytes=files[path],mime=String(blob?.mime??'');if(bytes&&mime.startsWith('image/'))portraitUrls.default=URL.createObjectURL(new Blob([Uint8Array.from(bytes)],{type:mime}));}}
  async function installCardPortraits(assets:CardAsset[]){clearPortraits();const modules=activeProjectId&&library?await library.boundAssetModules(activeProjectId):[],external=activeProjectId&&library?await library.moduleAssets(activeProjectId):[];boundModules=modules;galleryAssets=[...assets,...external];spriteGroups=buildNpcClusters(galleryAssets);const pictures=assets.filter(asset=>asset.bytes&&asset.mime.startsWith('image/')),icon=pictures.find(asset=>asset.type==='icon'&&normalize(asset.name)==='main')??pictures.find(asset=>asset.type==='icon')??pictures[0];if(icon)portraitUrls.default=cardAssetUrl(icon)??'';}
  function cardAssetUrl(asset:CardAsset){if(asset.url)return asset.url;if(asset.moduleId){void ensureModuleAsset(asset);return null;}if(!asset.bytes||!asset.mime.startsWith('image/'))return null;const key=`asset:${normalize(asset.path??asset.uri??asset.name??asset.type)}`,cached=portraitUrls[key];if(cached)return cached;const url=URL.createObjectURL(new Blob([Uint8Array.from(asset.bytes)],{type:asset.mime}));portraitUrls[key]=url;return url;}
  function assetUrlFor(asset:CardAsset){return cardAssetUrl(asset);}
  function requestAsset(name:string){const wanted=normalizeAssetName(name),asset=galleryAssets.find(value=>normalizeAssetName(value.name||value.type)===wanted||!!value.moduleNamespace&&normalizeAssetName(`${value.moduleNamespace}/${value.name}`)===wanted);if(asset?.moduleId)void ensureModuleAsset(asset);}
  async function ensureModuleAsset(asset:CardAsset){if(!library||!asset.moduleId||!asset.path||asset.url)return;const key=`${asset.moduleId}:${asset.path}`,existing=moduleLoads.get(key);if(existing)return existing;const work=(async()=>{const bytes=await library!.loadModuleAsset(asset);if(!bytes||!galleryAssets.includes(asset))return;const url=URL.createObjectURL(new Blob([Uint8Array.from(bytes)],{type:asset.mime}));asset.url=url;portraitUrls[`module:${key}`]=url;galleryAssets=[...galleryAssets];spriteGroups=buildNpcClusters(galleryAssets);version+=1;})().catch(reason=>{error=reason instanceof Error?reason.message:String(reason);}).finally(()=>moduleLoads.delete(key));moduleLoads.set(key,work);return work;}
  function portraitFor(id:string,emotion?:string){const sprite=findNpcSprite(spriteGroups,id,emotion??'default'),direct=galleryAssets.find(asset=>normalize(asset.name||asset.type)===normalize(id));return(sprite?assetUrlFor(sprite.asset):null)??(direct?assetUrlFor(direct):null)??portraitUrls.default??null;}
  // 리스처럼 카드 얼굴이 타일을 꽉 채우게 굽는다. cover만으로는 원본이 이미 좌우 여백을 품은 경우
  // 그 여백이 타일에 그대로 남는다(오너 피드백). 살짝 확대해 여백을 잘라내되, 인물 얼굴이 있는
  // 위쪽을 기준으로 둔다 — 정중앙 기준이면 확대할수록 머리가 잘린다.
  const THUMBNAIL_ZOOM=1.25,THUMBNAIL_FOCUS_Y=.3;
  async function makeCardThumbnail(parsed:ParsedCard){const pictures=parsed.assets.filter(asset=>asset.bytes&&asset.mime.startsWith('image/')),asset=pictures.find(value=>value.type==='icon'&&normalize(value.name)==='main')??pictures.find(value=>value.type==='icon')??null;if(!asset?.bytes)return'';const url=URL.createObjectURL(new Blob([Uint8Array.from(asset.bytes)],{type:asset.mime}));try{const image=new Image();image.src=url;await image.decode();const size=128,canvas=document.createElement('canvas');canvas.width=canvas.height=size;const context=canvas.getContext('2d');if(!context)return'';const scale=Math.max(size/image.naturalWidth,size/image.naturalHeight)*THUMBNAIL_ZOOM,width=image.naturalWidth*scale,height=image.naturalHeight*scale;context.drawImage(image,(size-width)/2,(size-height)*THUMBNAIL_FOCUS_Y,width,height);return canvas.toDataURL('image/webp',.82);}catch{return'';}finally{URL.revokeObjectURL(url);}}
  function normalize(v:string){return v.normalize('NFKC').toLowerCase().replace(/[\s./\\]+/g,'-');}
  function demo(){return new ProjectRuntime({projectId:'demo',schema:{initialState:{day:1}},screens:[{id:'play',title:'플레이',layout:'stage-chat-sidebar',regions:{main:[{widget:'chat'}]}}],navigation:[{id:'play',screenId:'play',label:'플레이'}],content:{},featureToggles:{},moduleIds:[]});}
</script>
